// Parse EDI integration names and filter to active EDI integrations
// Ported from extensions/celigo/src/server.py:_parse_edi_integration() and _is_edi_integration()

const includeStaging = $('MCP Trigger').first().json.include_staging || false;

function parseEdiIntegration(name) {
  // Detect staging: ends with (MM/DD/YYYY)
  const stagingMatch = name.match(/\((\d{1,2}\/\d{1,2}\/\d{4})\)\s*$/);
  const isStaging = stagingMatch !== null;
  const clean = name.replace(/\s*\(\d{1,2}\/\d{1,2}\/\d{4}\)\s*$/, '').trim();

  let network = 'direct';
  let partner = clean;
  if (clean.startsWith('EDI - VAN - ')) {
    network = 'VAN';
    partner = clean.slice('EDI - VAN - '.length);
  } else if (clean.startsWith('EDI - SPS - ')) {
    network = 'SPS';
    partner = clean.slice('EDI - SPS - '.length);
  } else if (clean.startsWith('EDI - ')) {
    partner = clean.slice('EDI - '.length);
  }

  return { partner, network, staging: isStaging, stagingDate: stagingMatch ? stagingMatch[1] : null };
}

const integrations = Array.isArray($input.first().json) 
  ? $input.first().json 
  : ($input.first().json.data || []);

const ediIntegrations = integrations
  .filter(i => i.name && i.name.startsWith('EDI'))
  .map(i => ({ ...parseEdiIntegration(i.name), _id: i._id, name: i.name, sandbox: i.sandbox, lastModified: i.lastModified }))
  .filter(i => includeStaging || !i.staging);

return ediIntegrations.map(i => ({ json: i }));

// Build the EDI health dashboard by combining:
// - EDI partner metadata (from Filter EDI Integrations)
// - Error counts (from Fetch Errors Per Partner — one item per partner)
// - Flow data (from Fetch All Flows — all flows in one response)
// Ported from extensions/celigo/src/server.py:celigo_get_edi_health_dashboard()

const DOC_TYPES = {
  '850': 'Purchase Order', '855': 'PO Acknowledgment', '856': 'ASN',
  '810': 'Invoice', '860': 'PO Change', '865': 'PO Change Ack',
  '997': 'Functional Ack', '940': 'Warehouse Shipping Order', 
  '945': 'Warehouse Shipping Advice',
};

function extractDocType(flowName) {
  const match = flowName.match(/\b(8[0-9]{2}|9[0-9]{2}|7[0-9]{2})\b/);
  return match ? match[1] : 'other';
}

const items = $input.all();

// Separate items: error responses have _flowId arrays, flow data has 'disabled'
// Partner metadata items were the input to Fetch Errors Per Partner
// Each item from Fetch Errors Per Partner has the partner's error array
// We need to reconstruct associations

// Get all flows from Fetch All Flows node
const allFlowsRaw = $('Fetch All Flows').first().json;
const allFlows = Array.isArray(allFlowsRaw) ? allFlowsRaw : (allFlowsRaw.data || []);

// Get EDI partner list from Filter EDI Integrations
const ediPartners = $('Filter EDI Integrations').all().map(i => i.json);

// items from current node are one per partner (error responses), in same order as ediPartners
// Build result by zipping partners with their error responses
const partnerRows = ediPartners.map((partner, idx) => {
  const errorResponse = items[idx] ? items[idx].json : [];
  const errors = Array.isArray(errorResponse) ? errorResponse : [];
  const totalErrors = errors.reduce((sum, e) => sum + (e.numError || 0), 0);

  // Get this partner's flows
  const partnerFlows = allFlows.filter(f => f._integrationId === partner._id);
  const activeFlows = partnerFlows.filter(f => !f.disabled);
  const disabledFlows = partnerFlows.filter(f => f.disabled);

  // Extract EDI doc types from flow names
  const docTypeSet = new Set();
  for (const f of partnerFlows) {
    const dt = extractDocType(f.name || '');
    if (dt !== 'other') docTypeSet.add(dt);
  }
  const docTypes = [...docTypeSet].sort();
  const docTypeLabels = docTypes.map(dt => DOC_TYPES[dt] ? `${dt} (${DOC_TYPES[dt]})` : dt);

  return {
    _id: partner._id,
    partner: partner.partner,
    network: partner.network,
    sandbox: partner.sandbox || false,
    total_flows: partnerFlows.length,
    active_flows: activeFlows.length,
    disabled_flows: disabledFlows.length,
    total_errors: totalErrors,
    doc_types: docTypeLabels,
  };
});

// Sort by errors desc, then partner name
partnerRows.sort((a, b) => {
  if (b.total_errors !== a.total_errors) return b.total_errors - a.total_errors;
  return a.partner.localeCompare(b.partner);
});

// Summary stats
const totalErrors = partnerRows.reduce((sum, p) => sum + p.total_errors, 0);
const partnersWithErrors = partnerRows.filter(p => p.total_errors > 0).length;
const totalActiveFlows = partnerRows.reduce((sum, p) => sum + p.active_flows, 0);

const result = {
  summary: {
    active_partners: partnerRows.length,
    partners_with_errors: partnersWithErrors,
    total_errors: totalErrors,
    total_active_flows: totalActiveFlows,
    generated_at: new Date().toISOString(),
  },
  partners: partnerRows,
};

// Byte safety — truncate if too large
const json = JSON.stringify(result);
if (json.length > 90000) {
  result.partners = result.partners.slice(0, 20);
  result.summary.truncated = true;
  result.summary.shown = result.partners.length;
}

return [{ json: result }];
